CREATE TABLE public.notifications (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID NOT NULL, type TEXT NOT NULL DEFAULT 'goal_reminder', title TEXT NOT NULL, body TEXT, goal_id UUID, read_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY; CREATE POLICY "notif_select_own" ON public.notifications FOR SELECT TO authenticated USING (auth.uid() = user_id); CREATE POLICY "notif_update_own" ON public.notifications FOR UPDATE TO authenticated USING (auth.uid() = user_id); CREATE POLICY "notif_delete_own" ON public.notifications FOR DELETE TO authenticated USING (auth.uid() = user_id); CREATE POLICY "notif_insert_own" ON public.notifications FOR INSERT TO authenticated WITH CHECK (auth.uid() = user_id); CREATE INDEX idx_notif_user ON public.notifications(user_id, created_at DESC); CREATE TABLE public.practice_plans (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID NOT NULL, title TEXT NOT NULL, steps JSONB NOT NULL DEFAULT '[]'::jsonb, status TEXT NOT NULL DEFAULT 'active', created_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.practice_plans ENABLE ROW LEVEL SECURITY; CREATE POLICY "plan_select_own" ON public.practice_plans FOR SELECT TO authenticated USING (auth.uid() = user_id); CREATE POLICY "plan_insert_own" ON public.practice_plans FOR INSERT TO authenticated WITH CHECK (auth.uid() = user_id); CREATE POLICY "plan_update_own" ON public.practice_plans FOR UPDATE TO authenticated USING (auth.uid() = user_id); CREATE POLICY "plan_delete_own" ON public.practice_plans FOR DELETE TO authenticated USING (auth.uid() = user_id); CREATE INDEX idx_plan_user ON public.practice_plans(user_id, created_at DESC);